-- Demo seed data for ValoMaths, dumped from the locally-seeded dev DB via pg_dump.
-- Regenerate with: docker exec webapp-postgres-1 pg_dump -U valorant -d valorant_igl_tutor --data-only --inserts --column-inserts --no-owner --no-privileges -t players -t matches -t match_players -t rounds -t round_player_stats -t kill_events -t impact_scores
